    "cases.compare_bids_and_award.step.award.out.recommendation": "Sopimussuositus",
    "cases.compare_bids_and_award.step.award.title": "Suosittele sopimuksen tekoa",
    "cases.compare_bids_and_award.step.award.what": "Laadi suositus: tasoitettu hintajakauma, kattavuus koko laajuuteen nähden, kaupallinen tai aikatauluriski, ja tarjoaja jonka valitsisit, perusteluineen lukujen rinnalla.",
    "cases.compare_bids_and_award.step.award.why": "Sopimuspäätöstä kyseenalaistaa johtaja, tarkastaja tai hävinnyt tarjoaja. Lyhyt selvitys, joka näyttää sekä laskennan että valinnan taustalla olevan harkinnan, sulkee sen keskustelun ennen kuin se alkaa.",
    "cases.compare_bids_and_award.step.level.in.bids": "Vahvistetut tarjoukset",
    "cases.compare_bids_and_award.step.level.in.psums": "Varaussummat",
