    "cases.compare_bids_and_award.step.open.out.verified": "Vahvistettu tarjoajalista",
    "cases.compare_bids_and_award.step.open.title": "Avaa tarjouspaketti",
    "cases.compare_bids_and_award.step.open.what": "Avaa tarjousaineisto, vahvista tarjoajalista sitä vasten ketä todella kutsuttiin, ja tarkista, että jokainen tarjous hinnoittelee saman luovutetun pohjan ja saman piirustusrevision.",
    "cases.compare_bids_and_award.step.open.why": "Vanhemmasta piirustussarjasta tai karsitusta pohjasta laskevat tarjoajat eivät kilpaile samasta työstä. Yhteisen lähtökohdan varmistaminen nyt pitää koko myöhemmän vertailun rehellisenä.",
    "cases.compare_bids_and_award.title": "Vertaile tarjouksia ja tee sopimuspäätös",
    "cases.compile_weekly_progress_report.desc": "Merkitse mihin aikataulu todella on edennyt, kerää viikon päiväkirjamerkinnät ja valokuvat, jotka sen todistavat, ja luovuta yksi rehellinen raportti, jonka tilaaja voi lukea kahdessa minuutissa.",
    "cases.compile_weekly_progress_report.step.actuals.in.programme": "Yleisaikataulu",
    "cases.compile_weekly_progress_report.step.actuals.in.week": "Tämän viikon edistyminen",
    "cases.compile_weekly_progress_report.step.actuals.out.percent": "Päivitetty valmiusaste",
    "cases.compile_weekly_progress_report.step.actuals.out.slippage": "Viivästymä lähtöaikatauluun nähden",
    "cases.compile_weekly_progress_report.step.actuals.title": "Päivitä edistyminen aikatauluun",
    "cases.compile_weekly_progress_report.step.actuals.what": "Käy aikataulu läpi ja aseta todellinen valmiusaste jokaiselle käynnissä olevalle tehtävälle, merkitse tämän viikon alkamiset ja valmistumiset, ja anna sen näyttää viivästymä lähtöaikatauluun nähden piilottamisen sijaan.",
    "cases.compile_weekly_progress_report.step.actuals.why": "Toiveikkaisiin prosenttilukuihin perustuva raportti pettää vain hetken ja tuhoaa uskottavuutesi kun totuus paljastuu. Rehelliset toteutumatiedot nyt tekevät ilmoittamastasi valmistumispäivästä uskottavan.",
    "cases.compile_weekly_progress_report.step.diary.in.entries": "Päiväkirjamerkinnät",
    "cases.compile_weekly_progress_report.step.diary.in.photos": "Työmaakuvat",
    "cases.compile_weekly_progress_report.step.diary.out.counts": "Työvoima- ja konelaskennat",
    "cases.compile_weekly_progress_report.step.diary.out.evidence": "Päivätty todistusaineisto",
    "cases.compile_weekly_progress_report.step.diary.title": "Kerää viikon todistusaineisto",
    "cases.compile_weekly_progress_report.step.diary.what": "Kerää viikon päiväkirjamerkinnät, työvoima- ja konelaskennat, sää sekä työmaakuvat, jotta ilmoittamasi edistyminen perustuu päivättyyn tallenteeseen siitä, mitä paikan päällä todella tapahtui.",
    "cases.compile_weekly_progress_report.step.diary.why": "Luku ilman todistusaineistoa on vain mielipide, jonka tilaaja voi kiistää. Päiväkirja ja valokuvat ovat myös se ajantasainen tallenne, joka painaa vaakakupissa jos viivästysvaatimusta väitellään kuukausien kuluttua.",
    "cases.compile_weekly_progress_report.step.publish.in.evidence": "Todistusaineisto",
