    "cases.produce_a_short_interval_lookahead.step.commit.out.ppc": "Pidettyjen lupausten pistemäärä",
    "cases.produce_a_short_interval_lookahead.step.commit.title": "Sovi viikkosuunnitelma",
    "cases.produce_a_short_interval_lookahead.step.commit.what": "Julkaise viikkotyösuunnitelma tehtävistä, jotka ovat aidosti valmiita, saa jokainen työnjohtaja sitoutumaan siihen mitä hänen ryhmänsä saa valmiiksi, ja mittaa viikon lopussa kuinka moni näistä lupauksista todella toteutui.",
    "cases.produce_a_short_interval_lookahead.step.commit.why": "Vain aidosti valmiin työn suunnittelu saa työryhmät luottamaan suunnitelmaan ja saavuttamaan sen. Pidettyjen lupausten seuranta viikko viikolta on rehellinen varhainen merkki siitä, onko aikataulu todella hallinnassa.",
    "cases.produce_a_short_interval_lookahead.step.constraints.in.blockers": "Tehtävän esteet",
    "cases.produce_a_short_interval_lookahead.step.constraints.in.tasks": "Ennakkokatsauksen tehtävät",
    "cases.produce_a_short_interval_lookahead.step.constraints.out.cleared": "Esteet poistettu",
    "cases.produce_a_short_interval_lookahead.step.constraints.out.ready": "Valmiit tehtävät",
    "cases.produce_a_short_interval_lookahead.step.constraints.title": "Poista esteet",
    "cases.produce_a_short_interval_lookahead.step.constraints.what": "Listaa jokaisesta tehtävästä, mitä täytyy olla kunnossa ennen aloitusta: suunnitelma julkaistu, materiaalit työmaalla, edeltävä työlaji valmis, lupa voimassa, kulkutie vapaa. Osoita jokainen este jollekulle ja ratkaise se ennen viikon alkua.",
    "cases.produce_a_short_interval_lookahead.step.constraints.why": "Tehtävä, joka lisätään suunnitelmaan ennen esteiden poistamista, on lupaus joka murtuu ja pysäyttää sitä seuraavat työlajit. Esteiden seulominen pois etukäteen tekee viikkositoumuksesta paperia parempaa.",
    "cases.produce_a_short_interval_lookahead.step.pull.in.programme": "Yleisaikataulu",
    "cases.produce_a_short_interval_lookahead.step.pull.in.window": "Kahden kolmen viikon ikkuna",
    "cases.produce_a_short_interval_lookahead.step.pull.out.lookahead": "Ennakkokatsauksen luonnos",
